// DuelGrid App.jsx - React-based tactical game with 8 characters per team, turn-based logic, abilities, and UI

import React, { useState } from 'react';
import './App.css';

const gridSize = 8;

const createCharacters = (team, yPos) => [
  { id: `${team}-1`, name: 'Knight', hp: 100, atk: 30, range: 1, type: 'melee', x: 0, y: yPos, sprite: `/sprites/knight.png`, team },
  { id: `${team}-2`, name: 'Archer', hp: 80, atk: 25, range: 3, type: 'ranged', x: 1, y: yPos, sprite: `/sprites/archer.png`, team },
  { id: `${team}-3`, name: 'Mage', hp: 70, atk: 40, range: 2, type: 'aoe', x: 2, y: yPos, sprite: `/sprites/mage.png`, team },
  { id: `${team}-4`, name: 'Healer', hp: 90, atk: -30, range: 2, type: 'heal', x: 3, y: yPos, sprite: `/sprites/healer.png`, team },
  { id: `${team}-5`, name: 'Warrior', hp: 110, atk: 35, range: 1, type: 'melee', x: 4, y: yPos, sprite: `/sprites/warrior.png`, team },
  { id: `${team}-6`, name: 'Rogue', hp: 75, atk: 30, range: 1, type: 'melee', x: 5, y: yPos, sprite: `/sprites/rogue.png`, team },
  { id: `${team}-7`, name: 'Summoner', hp: 65, atk: 45, range: 2, type: 'magic', x: 6, y: yPos, sprite: `/sprites/summoner.png`, team },
  { id: `${team}-8`, name: 'Paladin', hp: 95, atk: 20, range: 1, type: 'tank', x: 7, y: yPos, sprite: `/sprites/paladin.png`, team }
];

const initialCharacters = [
  ...createCharacters('A', 0),
  ...createCharacters('B', 7)
];

function App() {
  const [characters, setCharacters] = useState(initialCharacters);
  const [selectedId, setSelectedId] = useState(null);
  const [turn, setTurn] = useState('A');

  const currentChar = characters.find(c => c.id === selectedId);

  const moveCharacter = (id, dx, dy) => {
    setCharacters(prev =>
      prev.map(c => {
        if (c.id === id) {
          const newX = Math.max(0, Math.min(gridSize - 1, c.x + dx));
          const newY = Math.max(0, Math.min(gridSize - 1, c.y + dy));
          return { ...c, x: newX, y: newY };
        }
        return c;
      })
    );
    endTurn();
  };

  const endTurn = () => {
    setSelectedId(null);
    setTurn(prev => (prev === 'A' ? 'B' : 'A'));
  };

  const isInRange = (a, b, range) => Math.abs(a.x - b.x) + Math.abs(a.y - b.y) <= range;

  const attack = attackerId => {
    const attacker = characters.find(c => c.id === attackerId);
    let newChars = [...characters];

    if (attacker.type === 'heal') {
      newChars = newChars.map(c =>
        c.team === attacker.team && isInRange(attacker, c, attacker.range)
          ? { ...c, hp: Math.min(100, c.hp - attacker.atk) } : c);
    } else if (attacker.type === 'aoe') {
      newChars = newChars.map(c =>
        c.team !== attacker.team && isInRange(attacker, c, attacker.range)
          ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c);
    } else {
      const targets = newChars.filter(
        c => c.team !== attacker.team && isInRange(attacker, c, attacker.range)
      );
      if (targets.length > 0) {
        const target = targets[0];
        newChars = newChars.map(c =>
          c.id === target.id ? { ...c, hp: Math.max(0, c.hp - attacker.atk) } : c);
      }
    }

    setCharacters(newChars);
    endTurn();
  };

  return (
    <div className="App">
      <h1>DuelGrid</h1>
      <h2>Turn: Team {turn}</h2>
      <div className="grid">
        {Array.from({ length: gridSize }).map((_, y) => (
          <div key={y} className="row">
            {Array.from({ length: gridSize }).map((_, x) => {
              const char = characters.find(c => c.x === x && c.y === y);
              return (
                <div
                  key={x}
                  className={`tile ${char ? 'occupied' : ''}`}
                  onClick={() => char && char.team === turn && setSelectedId(char.id)}
                >
                  {char && (
                    <div className="character">
                      <img src={char.sprite} alt={char.name} className="sprite" />
                      <div className="stats">
                        <div>{char.name}</div>
                        <div>HP: {char.hp}</div>
                      </div>
                    </div>
                  )}
                </div>
              );
            })}
          </div>
        ))}
      </div>
      <div className="controls">
        {selectedId && (
          <>
            <button onClick={() => moveCharacter(selectedId, -1, 0)}>←</button>
            <button onClick={() => moveCharacter(selectedId, 1, 0)}>→</button>
            <button onClick={() => moveCharacter(selectedId, 0, -1)}>↑</button>
            <button onClick={() => moveCharacter(selectedId, 0, 1)}>↓</button>
            <button onClick={() => attack(selectedId)}>Action</button>
          </>
        )}
      </div>
    </div>
  );
}

export default App;
